import os,time,sys
def loadenv(p):
    if not os.path.exists(p): return
    for raw in open(p):
        t=raw.strip()
        if not t or t.startswith('#'): continue
        if t.lower().startswith('export '): t=t[7:]
        if '=' in t:
            k,v=t.split('=',1); os.environ.setdefault(k.strip(), v.strip().strip('"').strip("'"))
loadenv('/etc/atlas/db.env')
import psycopg2
def g(*n):
    for x in n:
        if os.environ.get(x): return os.environ[x]
    return None
i=0
while i<150:
    try:
        c=psycopg2.connect(host=g('PGHOST','DB_HOST') or 'localhost', port=g('PGPORT','DB_PORT') or '5432',
                           dbname=g('PGDATABASE','DB_NAME') or 'tuanichat_atlas', user=g('PGUSER','DB_USER') or 'atlas',
                           password=g('PGPASSWORD','DB_PASSWORD'), connect_timeout=5)
        cur=c.cursor(); cur.execute('SELECT 1'); cur.fetchone(); c.close()
        print('PG READY after %ds'%i); sys.exit(0)
    except Exception as e:
        sys.stderr.write('waiting for PG (%ds): %s\n'%(i,str(e)[:80])); time.sleep(5); i+=5
sys.stderr.write('PG NOT READY after 150s\n'); sys.exit(7)
